import{_ as r,o as t,c as e,an as a}from"./chunks/framework.CwJEbcdc.js";const u=JSON.parse('{"title":"提示工程简介 (Introduction)","description":"","frontmatter":{},"headers":[],"relativePath":"AI/prompt-engineering-introduction.md","filePath":"AI/prompt-engineering-introduction.md","lastUpdated":1771699698000}'),s={name:"AI/prompt-engineering-introduction.md"};function o(i,n,l,p,g,d){return t(),e("div",null,[...n[0]||(n[0]=[a(`<h1 id="提示工程简介-introduction" tabindex="-1">提示工程简介 (Introduction) <a class="header-anchor" href="#提示工程简介-introduction" aria-label="Permalink to “提示工程简介 (Introduction)”">​</a></h1><p><strong>提示工程 (Prompt Engineering)</strong> 是一门专注于开发和优化提示词（Prompts）的新兴学科，旨在帮助用户在各种应用场景中高效地利用大语言模型（LLMs）进行构建与应用。</p><p>掌握提示工程不仅能提高生产力，还能让我们更深入地理解 LLMs 的能力边界与局限性。</p><ul><li><strong>研究人员</strong>：利用提示工程在问答、算术推理等各类常规及复杂任务中，显著提升模型的能力并增强其安全性。</li><li><strong>开发人员</strong>：通过提示工程设计出更稳健、高效的提示技术，从而实现 LLMs 与其他工具及系统的完美对接。</li></ul><p>本指南提供了一份全面的参考资料，涵盖了提示工程的理论基础与实战技巧，旨在通过最佳的交互策略，帮助你充分发挥 LLMs 的潜力。</p><h2 id="实验环境配置" tabindex="-1">实验环境配置 <a class="header-anchor" href="#实验环境配置" aria-label="Permalink to “实验环境配置”">​</a></h2><p>除非另有说明，本指南中的所有示例均在 <a href="https://platform.openai.com/playground" target="_blank" rel="noreferrer">OpenAI Playground</a> 中使用 <code>gpt-3.5-turbo</code> 模型测试完成。模型采用了默认配置项：</p><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>模型型号: gpt-3.5-turbo</span></span>
<span class="line"><span>温度系数 (Temperature): 1</span></span>
<span class="line"><span>核采样 (Top-P): 1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这些提示词策略原则上同样适用于其他具备同等能力的模型，不过实际生成的响应结果可能会因模型差异而有所不同。</p><h2 id="💡-核心总结-core-summary" tabindex="-1">💡 核心总结 (Core Summary) <a class="header-anchor" href="#💡-核心总结-core-summary" aria-label="Permalink to “💡 核心总结 (Core Summary)”">​</a></h2><ul><li><strong>核心定义</strong>：提示工程是研究如何<strong>开发与优化提示词</strong>以高效应用 LLMs 的学科。</li><li><strong>双重价值</strong>：既能提升<strong>生产力</strong>，又能帮助我们摸清模型的<strong>能力边界</strong>。</li><li><strong>应用分工</strong>： <ul><li><strong>研究者</strong>：关注模型的<strong>安全性</strong>与复杂逻辑推理能力。</li><li><strong>开发者</strong>：关注如何设计<strong>稳健的接口</strong>与其内部系统对接。</li></ul></li></ul><hr><blockquote><p>原文链接: <a href="https://www.promptingguide.ai/introduction" target="_blank" rel="noreferrer">Introduction | Prompt Engineering Guide</a></p></blockquote>`,13)])])}const m=r(s,[["render",o]]);export{u as __pageData,m as default};
